/**
 * Auth Gate — Client-side password protection for static sites
 *
 * Generated by surge-deploy. Replace __HASH_PLACEHOLDER__ with the SHA-256 hash of your password.
 * Hash generation: echo -n "yourpassword" | shasum -a 256 | cut -d' ' -f1
 */
(function () {
  'use strict';

  var EXPECTED_HASH = '__HASH_PLACEHOLDER__';
  var STORAGE_KEY = 'surge_auth_hash';

  // Check existing auth
  try {
    if (localStorage.getItem(STORAGE_KEY) === EXPECTED_HASH) return;
  } catch (e) { /* localStorage blocked — continue to prompt */ }

  // Hide page content immediately
  var hideStyle = document.createElement('style');
  hideStyle.textContent = 'body > *:not(#auth-gate) { visibility: hidden !important; }';
  document.head.appendChild(hideStyle);

  // SHA-256 hash function using Web Crypto API
  function sha256(str) {
    var encoder = new TextEncoder();
    var data = encoder.encode(str);
    return crypto.subtle.digest('SHA-256', data).then(function (buffer) {
      var hashArray = Array.from(new Uint8Array(buffer));
      return hashArray.map(function (b) { return b.toString(16).padStart(2, '0'); }).join('');
    });
  }

  function mountOverlay() {
    var overlay = document.createElement('div');
    overlay.id = 'auth-gate';
    overlay.innerHTML = [
      '<style>',
      '#auth-gate {',
      '  position: fixed; inset: 0; z-index: 999999;',
      '  background: #111;',
      '  display: flex; align-items: center; justify-content: center;',
      '  font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;',
      '}',
      '#auth-gate * { margin: 0; padding: 0; box-sizing: border-box; }',
      '#auth-gate .ag-card {',
      '  position: relative;',
      '  background: #1a1a1a;',
      '  border: 1px solid #333;',
      '  border-radius: 12px;',
      '  padding: 40px 32px;',
      '  max-width: 380px; width: 90%;',
      '  text-align: center;',
      '  animation: ag-fadeIn 0.4s ease;',
      '}',
      '@keyframes ag-fadeIn {',
      '  from { opacity: 0; transform: translateY(8px); }',
      '  to { opacity: 1; transform: translateY(0); }',
      '}',
      '@keyframes ag-shake {',
      '  0%, 100% { transform: translateX(0); }',
      '  15%, 45%, 75% { transform: translateX(-6px); }',
      '  30%, 60%, 90% { transform: translateX(6px); }',
      '}',
      '#auth-gate .ag-icon {',
      '  font-size: 2rem; margin-bottom: 16px;',
      '}',
      '#auth-gate .ag-title {',
      '  font-size: 1.25rem; font-weight: 600; color: #e5e5e5;',
      '  margin-bottom: 4px;',
      '}',
      '#auth-gate .ag-subtitle {',
      '  font-size: 0.8rem; color: #888; margin-bottom: 24px;',
      '}',
      '#auth-gate .ag-input {',
      '  width: 100%; padding: 10px 14px;',
      '  background: #222;',
      '  border: 1px solid #333;',
      '  border-radius: 8px;',
      '  color: #e5e5e5;',
      '  font-family: ui-monospace, "SF Mono", monospace;',
      '  font-size: 0.9rem;',
      '  outline: none;',
      '  transition: border-color 0.2s;',
      '  margin-bottom: 12px;',
      '}',
      '#auth-gate .ag-input:focus {',
      '  border-color: #555;',
      '}',
      '#auth-gate .ag-input::placeholder {',
      '  color: #666;',
      '}',
      '#auth-gate .ag-btn {',
      '  width: 100%; padding: 10px;',
      '  background: #e5e5e5;',
      '  border: none; border-radius: 8px;',
      '  color: #111; font-weight: 500;',
      '  font-size: 0.85rem;',
      '  cursor: pointer;',
      '  transition: background 0.2s;',
      '}',
      '#auth-gate .ag-btn:hover { background: #d4d4d4; }',
      '#auth-gate .ag-btn:active { background: #c4c4c4; }',
      '#auth-gate .ag-error {',
      '  font-size: 0.75rem; color: #ef4444; margin-top: 12px;',
      '  opacity: 0; transition: opacity 0.2s;',
      '}',
      '#auth-gate .ag-error.visible { opacity: 1; }',
      '#auth-gate .ag-footer {',
      '  margin-top: 24px; font-size: 0.65rem; color: #555;',
      '  letter-spacing: 0.04em;',
      '}',
      '</style>',
      '<div class="ag-card">',
      '  <div class="ag-icon">&#128274;</div>',
      '  <div class="ag-title">Protected Content</div>',
      '  <div class="ag-subtitle">Enter the password to continue</div>',
      '  <form id="ag-form" autocomplete="off">',
      '    <input class="ag-input" type="password" id="ag-password" placeholder="Password" autocomplete="off" autofocus>',
      '    <button class="ag-btn" type="submit">Continue</button>',
      '    <div class="ag-error" id="ag-error">Incorrect password</div>',
      '  </form>',
      '  <div class="ag-footer">Protected Content</div>',
      '</div>'
    ].join('\n');

    document.body.appendChild(overlay);

    var form = document.getElementById('ag-form');
    var input = document.getElementById('ag-password');
    var error = document.getElementById('ag-error');
    var card = overlay.querySelector('.ag-card');

    form.addEventListener('submit', function (e) {
      e.preventDefault();
      var password = input.value;
      if (!password) return;

      sha256(password).then(function (hash) {
        if (hash === EXPECTED_HASH) {
          try { localStorage.setItem(STORAGE_KEY, hash); } catch (ex) { /* ok */ }
          overlay.remove();
          hideStyle.remove();
        } else {
          error.classList.add('visible');
          card.style.animation = 'none';
          void card.offsetHeight;
          card.style.animation = 'ag-shake 0.5s ease';
          input.value = '';
          input.focus();
          setTimeout(function () { card.style.animation = ''; }, 500);
        }
      });
    });

    input.focus();
  }

  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', mountOverlay);
  } else {
    mountOverlay();
  }
})();
